self.__next_f.push([1,"rovides a surprisingly simple way to make virtually any DOM element draggable, spinnable, tossable, and even flick-scrollable using mouse and/or touch events. It integrates beautifully with InertiaPlugin so that the user can flick and have the motion decelerate smoothly based on momentum.\n\t\u003c/p\u003e\n\n\t\u003ch3\u003e\n\t\tMinimal Usage\n\t\u003c/h3\u003e\n\n\t\u003cpre class=\"ipsCode prettyprint lang-javascript prettyprinted\" id=\"ips_uid_7278_8\" style=\"\"\u003e\u003cspan class=\"typ\"\u003eDraggable\u003c/span\u003e\u003cspan class=\"pun\"\u003e.\u003c/span\u003e\u003cspan class=\"pln\"\u003ecreate\u003c/span\u003e\u003cspan class=\"pun\"\u003e(\u003c/span\u003e\u003cspan class=\"str\"\u003e\".flair--4b\"\u003c/span\u003e\u003cspan class=\"pun\"\u003e,\u003c/span\u003e\u003cspan class=\"pln\"\u003e \u003c/span\u003e\u003cspan class=\"pun\"\u003e{\u003c/span\u003e\u003cspan class=\"pln\"\u003e\n  bounds\u003c/span\u003e\u003cspan class=\"pun\"\u003e:\u003c/span\u003e\u003cspan class=\"pln\"\u003e \u003c/span\u003e\u003cspan class=\"str\"\u003e\".container\"\u003c/span\u003e\u003cspan class=\"pun\"\u003e,\u003c/span\u003e\u003cspan class=\"pln\"\u003e\n  inertia\u003c/span\u003e\u003cspan class=\"pun\"\u003e:\u003c/span\u003e\u003cspan class=\"pln\"\u003e \u003c/span\u003e\u003cspan class=\"kwd\"\u003etrue\u003c/span\u003e\u003cspan class=\"pln\"\u003e\n\u003c/span\u003e\u003cspan class=\"pun\"\u003e});\u003c/span\u003e\u003c/pre\u003e\n\n\t\u003ch3\u003e\n\t\tTry it out\n\t\u003c/h3\u003e\n\t\u003ciframe allowtransparency=\"true\" frameborder=\"no\" height=\"300\" loading=\"lazy\" scrolling=\"no\" src=\"https://codepen.io/GreenSock/embed/yLGqXzZ?default-tab=result\u0026amp;editable=true\u0026amp;theme-id=41197\" style=\"width: 100%;\" title=\"Draggable Demo\"\u003eSee the Pen Draggable Demo by GSAP (@GreenSock) on CodePen.\u003c/iframe\u003e\n\u003c/div\u003e\nf:Tabb,"])

