self.__next_f.push([1,"\u003cdiv\u003e\n\t\u003ch2\u003e\n\t\tSplitText\n\t\u003c/h2\u003e\n\n\t\u003cp\u003e\n\t\tSplitText is a small JavaScript library that splits an HTML element's text into individual characters, words, and/or lines (each in its own, newly-created element), allowing you to create gorgeous staggered animations.\n\t\u003c/p\u003e\n\n\t\u003ch3\u003e\n\t\tMinimal usage\n\t\u003c/h3\u003e\n\n\t\u003cpre class=\"ipsCode prettyprint lang-javascript prettyprinted\" id=\"ips_uid_5919_8\" style=\"\"\u003e\u003cspan class=\"com\"\u003e// split elements with the class \"split\" into words and characters\u003c/span\u003e\u003cspan class=\"pln\"\u003e\n\u003c/span\u003e\u003cspan class=\"kwd\"\u003elet\u003c/span\u003e\u003cspan class=\"pln\"\u003e split \u003c/span\u003e\u003cspan class=\"pun\"\u003e=\u003c/span\u003e\u003cspan class=\"pln\"\u003e \u003c/span\u003e\u003cspan class=\"typ\"\u003eSplitText\u003c/span\u003e\u003cspan class=\"pun\"\u003e.\u003c/span\u003e\u003cspan class=\"pln\"\u003ecreate\u003c/span\u003e\u003cspan class=\"pun\"\u003e(\u003c/span\u003e\u003cspan class=\"str\"\u003e\".split\"\u003c/span\u003e\u003cspan class=\"pun\"\u003e,\u003c/span\u003e\u003cspan class=\"pln\"\u003e \u003c/span\u003e\u003cspan class=\"pun\"\u003e{\u003c/span\u003e\u003cspan class=\"pln\"\u003e type\u003c/span\u003e\u003cspan class=\"pun\"\u003e:\u003c/span\u003e\u003cspan class=\"pln\"\u003e \u003c/span\u003e\u003cspan class=\"str\"\u003e\"words, chars\"\u003c/span\u003e\u003cspan class=\"pln\"\u003e \u003c/span\u003e\u003cspan class=\"pun\"\u003e});\u003c/span\u003e\u003cspan class=\"pln\"\u003e\n\n\u003c/span\u003e\u003cspan class=\"com\"\u003e// now animate the characters in a staggered fashion\u003c/span\u003e\u003cspan class=\"pln\"\u003e\ngsap\u003c/span\u003e\u003cspan class=\"pun\"\u003e.\u003c/span\u003e\u003cspan class=\"pln\"\u003efrom\u003c/span\u003e\u003cspan class=\"pun\"\u003e(\u003c/span\u003e\u003cspan class=\"pln\"\u003esplit\u003c/span\u003e\u003cspan class=\"pun\"\u003e.\u003c/span\u003e\u003cspan class=\"pln\"\u003echars\u003c/span\u003e\u003cspan class=\"pun\"\u003e,\u003c/span\u003e\u003cspan class=\"pln\"\u003e \u003c/span\u003e\u003cspan class=\"pun\"\u003e{\u003c/span\u003e\u003cspan class=\"pln\"\u003e\n  duration\u003c/span\u003e\u003cspan class=\"pun\"\u003e:\u003c/span\u003e\u003cspan class=\"pln\"\u003e \u003c/span\u003e\u003cspan class=\"lit\"\u003e1\u003c/span\u003e\u003cspan class=\"pun\"\u003e,\u003c/span\u003e\u003cspan class=\"pln\"\u003e \n  y\u003c/span\u003e\u003cspan class=\"pun\"\u003e:\u003c/span\u003e\u003cspan class=\"pln\"\u003e \u003c/span\u003e\u003cspan class=\"lit\"\u003e100\u003c/span\u003e\u003cspan class=\"pun\"\u003e,\u003c/span\u003e\u003cspan class=\"pln\"\u003e       \u003c/span\u003e\u003cspan class=\"com\"\u003e// animate from 100px below\u003c/span\u003e\u003cspan class=\"pln\"\u003e\n  autoAlpha\u003c/span\u003e\u003cspan class=\"pun\"\u003e:\u003c/span\u003e\u003cspan class=\"pln\"\u003e \u003c/span\u003e\u003cspan class=\"lit\"\u003e0\u003c/span\u003e\u003cspan class=\"pun\"\u003e,\u003c/span\u003e\u003cspan class=\"pln\"\u003e \u003c/span\u003e\u003cspan class=\"com\"\u003e// fade in from opacity: 0 and visibility: hidden\u003c/span\u003e\u003cspan class=\"pln\"\u003e\n  stagger\u003c/span\u003e\u003cspan class=\"pun\"\u003e:\u003c/span\u003e\u003cspan class=\"pln\"\u003e \u003c/span\u003e\u003cspan class=\"lit\"\u003e0.05\u003c/span\u003e\u003cspan class=\"pln\"\u003e \u003c/span\u003e\u003cspan class=\"com\"\u003e// 0.05 seconds between each\u003c/span\u003e\u003cspan class=\"pln\"\u003e\n\u003c/span\u003e\u003cspan class=\"pun\"\u003e});\u003c/span\u003e\u003c/pre\u003e\n\n\t\u003cp\u003e\n\t\t \n\t\u003c/p\u003e\n\u003c/div\u003e\n"])

