self.__next_f.push([1,"\u003cdiv\u003e\n\t\u003ch2\u003e\n\t\tControl methods\n\t\u003c/h2\u003e\n\n\t\u003cp\u003e\n\t\tControl methods are handy when you need a little more control over your animation. A common use case is to play an animation on a certain interaction like a button click or hover.\n\t\u003c/p\u003e\n\n\t\u003cp\u003e\n\t\tControl methods can be used on both tweens and timelines and allow you to play, pause, reverse or even speed up your animations.\n\t\u003c/p\u003e\n\n\t\u003cpre class=\"ipsCode prettyprint lang-javascript prettyprinted\" id=\"ips_uid_1394_8\" style=\"\"\u003e\u003cspan class=\"com\"\u003e// store the tween or timeline in a variable\u003c/span\u003e\u003cspan class=\"pln\"\u003e\n\u003c/span\u003e\u003cspan class=\"kwd\"\u003elet\u003c/span\u003e\u003cspan class=\"pln\"\u003e tween \u003c/span\u003e\u003cspan class=\"pun\"\u003e=\u003c/span\u003e\u003cspan class=\"pln\"\u003e gsap\u003c/span\u003e\u003cspan class=\"pun\"\u003e.\u003c/span\u003e\u003cspan class=\"pln\"\u003eto\u003c/span\u003e\u003cspan class=\"pun\"\u003e(\u003c/span\u003e\u003cspan class=\"str\"\u003e\"#logo\"\u003c/span\u003e\u003cspan class=\"pun\"\u003e,\u003c/span\u003e\u003cspan class=\"pln\"\u003e \u003c/span\u003e\u003cspan class=\"pun\"\u003e{\u003c/span\u003e\u003cspan class=\"pln\"\u003eduration\u003c/span\u003e\u003cspan class=\"pun\"\u003e:\u003c/span\u003e\u003cspan class=\"pln\"\u003e \u003c/span\u003e\u003cspan class=\"lit\"\u003e1\u003c/span\u003e\u003cspan class=\"pun\"\u003e,\u003c/span\u003e\u003cspan class=\"pln\"\u003e x\u003c/span\u003e\u003cspan class=\"pun\"\u003e:\u003c/span\u003e\u003cspan class=\"pln\"\u003e \u003c/span\u003e\u003cspan class=\"lit\"\u003e100\u003c/span\u003e\u003cspan class=\"pun\"\u003e});\u003c/span\u003e\u003cspan class=\"pln\"\u003e\n\n\u003c/span\u003e\u003cspan class=\"com\"\u003e//pause\u003c/span\u003e\u003cspan class=\"pln\"\u003e\ntween\u003c/span\u003e\u003cspan class=\"pun\"\u003e.\u003c/span\u003e\u003cspan class=\"pln\"\u003epause\u003c/span\u003e\u003cspan class=\"pun\"\u003e();\u003c/span\u003e\u003cspan class=\"pln\"\u003e\n\n\u003c/span\u003e\u003cspan class=\"com\"\u003e//resume (honors direction - reversed or not)\u003c/span\u003e\u003cspan class=\"pln\"\u003e\ntween\u003c/span\u003e\u003cspan class=\"pun\"\u003e.\u003c/span\u003e\u003cspan class=\"pln\"\u003eresume\u003c/span\u003e\u003cspan class=\"pun\"\u003e();\u003c/span\u003e\u003cspan class=\"pln\"\u003e\n\n\u003c/span\u003e\u003cspan class=\"com\"\u003e//reverse (always goes back towards the beginning)\u003c/span\u003e\u003cspan class=\"pln\"\u003e\ntween\u003c/span\u003e\u003cspan class=\"pun\"\u003e.\u003c/span\u003e\u003cspan class=\"pln\"\u003ereverse\u003c/span\u003e\u003cspan class=\"pun\"\u003e();\u003c/span\u003e\u003cspan class=\"pln\"\u003e\n\n\u003c/span\u003e\u003cspan class=\"com\"\u003e//jump to exactly 0.5 seconds into the tween\u003c/span\u003e\u003cspan class=\"pln\"\u003e\ntween\u003c/span\u003e\u003cspan class=\"pun\"\u003e.\u003c/span\u003e\u003cspan class=\"pln\"\u003eseek\u003c/span\u003e\u003cspan class=\"pun\"\u003e(\u003c/span\u003e\u003cspan class=\"lit\"\u003e0.5\u003c/span\u003e\u003cspan class=\"pun\"\u003e);\u003c/span\u003e\u003cspan class=\"pln\"\u003e\n\n\u003c/span\u003e\u003cspan class=\"com\"\u003e//jump to exacty 1/4th into the tween 's progress:\u003c/span\u003e\u003cspan class=\"pln\"\u003e\ntween\u003c/span\u003e\u003cspan class=\"pun\"\u003e.\u003c/span\u003e\u003cspan class=\"pln\"\u003eprogress\u003c/span\u003e\u003cspan class=\"pun\"\u003e(\u003c/span\u003e\u003cspan class=\"lit\"\u003e0.25\u003c/span\u003e\u003cspan class=\"pun\"\u003e);\u003c/span\u003e\u003cspan class=\"pln\"\u003e\n\n\u003c/span\u003e\u003cspan class=\"com\"\u003e//make the tween go half-speed\u003c/span\u003e\u003cspan class=\"pln\"\u003e\ntween\u003c/span\u003e\u003cspan class=\"pun\"\u003e.\u003c/span\u003e\u003cspan class=\"pln\"\u003etimeScale\u003c/span\u003e\u003cspan class=\"pun\"\u003e(\u003c/span\u003e\u003cspan class=\"lit\"\u003e0.5\u003c/span\u003e\u003cspan class=\"pun\"\u003e);\u003c/span\u003e\u003cspan class=\"pln\"\u003e\n\n\u003c/span\u003e\u003cspan class=\"com\"\u003e//make the tween go double-speed\u003c/span\u003e\u003cspan class=\"pln\"\u003e\ntween\u003c/span\u003e\u003cspan class=\"pun\"\u003e.\u003c/span\u003e\u003cspan class=\"pln\"\u003etimeScale\u003c/span\u003e\u003cspan class=\"pun\"\u003e(\u003c/span\u003e\u003cspan class=\"lit\"\u003e2\u003c/span\u003e\u003cspan class=\"pun\"\u003e);\u003c/span\u003e\u003cspan class=\"pln\"\u003e\n\n\u003c/span\u003e\u003cspan class=\"com\"\u003e//immediately kill the tween and make it eligible for garbage collection\u003c/span\u003e\u003cspan class=\"pln\"\u003e\ntween\u003c/span\u003e\u003cspan class=\"pun\"\u003e.\u003c/span\u003e\u003cspan class=\"pln\"\u003ekill\u003c/span\u003e\u003cspan class=\"pun\"\u003e();\u003c/span\u003e\u003cspan class=\"pln\"\u003e\n\n\u003c/span\u003e\u003cspan class=\"com\"\u003e// You can even chain control methods\u003c/span\u003e\u003cspan class=\"pln\"\u003e\n\u003c/span\u003e\u003cspan class=\"com\"\u003e// Play the timeline at double speed - in reverse.\u003c/span\u003e\u003cspan class=\"pln\"\u003e\ntween\u003c/span\u003e\u003cspan class=\"pun\"\u003e.\u003c/span\u003e\u003cspan class=\"pln\"\u003etimeScale\u003c/span\u003e\u003cspan class=\"pun\"\u003e(\u003c/span\u003e\u003cspan class=\"lit\"\u003e2\u003c/span\u003e\u003cspan class=\"pun\"\u003e).\u003c/span\u003e\u003cspan class=\"pln\"\u003ereverse\u003c/span\u003e\u003cspan class=\"pun\"\u003e();\u003c/span\u003e\u003c/pre\u003e\n\n\t\u003cp\u003e\n\t\t \n\t\u003c/p\u003e\n\u003c/div\u003e\n"])

