self.__next_f.push([1,"\u003cdiv\u003e\n\t\u003ch2\u003e\n\t\tMatchMedia\n\t\u003c/h2\u003e\n\n\t\u003cp\u003e\n\t\tMatchMedia is the easiest way to make responsive, accessible animations and ScrollTriggers. \u003ccode\u003e\u003ca href=\"https://greensock.com/docs/v3/GSAP/gsap.matchMedia()\" rel=\"external nofollow\"\u003egsap.matchMedia()\u003c/a\u003e\u003c/code\u003e lets you tuck setup code into a function that only executes when a particular \u003ca href=\"https://developer.mozilla.org/en-US/docs/Web/CSS/Media_Queries/Using_media_queries\" rel=\"external nofollow\" target=\"_blank\"\u003emedia query\u003c/a\u003e matches and then when it no longer matches, all the GSAP animations and ScrollTriggers created during that function's execution get \u003cstrong\u003ereverted automatically\u003c/strong\u003e! Customizing for mobile/desktop or \u003ccode\u003eprefers-reduced-motion\u003c/code\u003e accessibility is remarkably simple.\n\t\u003c/p\u003e\n\n\t\u003ch3\u003e\n\t\tExample setup\n\t\u003c/h3\u003e\n\n\t\u003cpre class=\"ipsCode prettyprint lang-javascript prettyprinted\" id=\"ips_uid_1862_8\" style=\"\"\u003e\u003cspan class=\"com\"\u003e// create\u003c/span\u003e\u003cspan class=\"pln\"\u003e\n\u003c/span\u003e\u003cspan class=\"kwd\"\u003elet\u003c/span\u003e\u003cspan class=\"pln\"\u003e mm \u003c/span\u003e\u003cspan class=\"pun\"\u003e=\u003c/span\u003e\u003cspan class=\"pln\"\u003e gsap\u003c/span\u003e\u003cspan class=\"pun\"\u003e.\u003c/span\u003e\u003cspan class=\"pln\"\u003ematchMedia\u003c/span\u003e\u003cspan class=\"pun\"\u003e();\u003c/span\u003e\u003cspan class=\"pln\"\u003e\n\n\u003c/span\u003e\u003cspan class=\"com\"\u003e// add a media query. When it matches, the associated function will run\u003c/span\u003e\u003cspan class=\"pln\"\u003e\nmm\u003c/span\u003e\u003cspan class=\"pun\"\u003e.\u003c/span\u003e\u003cspan class=\"pln\"\u003eadd\u003c/span\u003e\u003cspan class=\"pun\"\u003e(\u003c/span\u003e\u003cspan class=\"str\"\u003e\"(min-width: 800px)\"\u003c/span\u003e\u003cspan class=\"pun\"\u003e,\u003c/span\u003e\u003cspan class=\"pln\"\u003e \u003c/span\u003e\u003cspan class=\"pun\"\u003e()\u003c/span\u003e\u003cspan class=\"pln\"\u003e \u003c/span\u003e\u003cspan class=\"pun\"\u003e=\u0026gt;\u003c/span\u003e\u003cspan class=\"pln\"\u003e \u003c/span\u003e\u003cspan class=\"pun\"\u003e{\u003c/span\u003e\u003cspan class=\"pln\"\u003e\n\n  \u003c/span\u003e\u003cspan class=\"com\"\u003e// this setup code only runs when viewport is at least 800px wide\u003c/span\u003e\u003cspan class=\"pln\"\u003e\n  gsap\u003c/span\u003e\u003cspan class=\"pun\"\u003e.\u003c/span\u003e\u003cspan class=\"pln\"\u003eto\u003c/span\u003e\u003cspan class=\"pun\"\u003e(...);\u003c/span\u003e\u003cspan class=\"pln\"\u003e\n  gsap\u003c/span\u003e\u003cspan class=\"pun\"\u003e.\u003c/span\u003e\u003cspan class=\"pln\"\u003efrom\u003c/span\u003e\u003cspan class=\"pun\"\u003e(...);\u003c/span\u003e\u003cspan class=\"pln\"\u003e\n  \u003c/span\u003e\u003cspan class=\"typ\"\u003eScrollTrigger\u003c/span\u003e\u003cspan class=\"pun\"\u003e.\u003c/span\u003e\u003cspan class=\"pln\"\u003ecreate\u003c/span\u003e\u003cspan class=\"pun\"\u003e({...});\u003c/span\u003e\u003cspan class=\"pln\"\u003e\n\n  \u003c/span\u003e\u003cspan class=\"kwd\"\u003ereturn\u003c/span\u003e\u003cspan class=\"pln\"\u003e \u003c/span\u003e\u003cspan class=\"pun\"\u003e()\u003c/span\u003e\u003cspan class=\"pln\"\u003e \u003c/span\u003e\u003cspan class=\"pun\"\u003e=\u0026gt;\u003c/span\u003e\u003cspan class=\"pln\"\u003e \u003c/span\u003e\u003cspan class=\"pun\"\u003e{\u003c/span\u003e\u003cspan class=\"pln\"\u003e \u003c/span\u003e\u003cspan class=\"com\"\u003e// optional\u003c/span\u003e\u003cspan class=\"pln\"\u003e\n    \u003c/span\u003e\u003cspan class=\"com\"\u003e// custom cleanup code here (runs when it STOPS matching)\u003c/span\u003e\u003cspan class=\"pln\"\u003e\n  \u003c/span\u003e\u003cspan class=\"pun\"\u003e};\u003c/span\u003e\u003cspan class=\"pln\"\u003e\n\u003c/span\u003e\u003cspan class=\"pun\"\u003e});\u003c/span\u003e\u003cspan class=\"pln\"\u003e\n\n\u003c/span\u003e\u003cspan class=\"com\"\u003e// later, if we need to revert all the animations/ScrollTriggers...\u003c/span\u003e\u003cspan class=\"pln\"\u003e\nmm\u003c/span\u003e\u003cspan class=\"pun\"\u003e.\u003c/span\u003e\u003cspan class=\"pln\"\u003erevert\u003c/span\u003e\u003cspan class=\"pun\"\u003e();\u003c/span\u003e\u003c/pre\u003e\n\n\t\u003cp\u003e\n\t\t \n\t\u003c/p\u003e\n\u003c/div\u003e\n"])

