self.__next_f.push([1,"\u003cdiv\u003e\n\t\u003ch2\u003e\n\t\tAnimate a 3D element between layout positions on scroll\n\t\u003c/h2\u003e\n\n\t\u003cp\u003e\n\t\tWe get asked how to animate a 3D object between waypoints in a page \u003cstrong\u003ea lot\u003c/strong\u003e in the GSAP forums. It is especially \u003ca href=\"https://silencio.es/\" rel=\"external nofollow\"\u003epopular\u003c/a\u003e with \u003ca href=\"https://keefbrands.com/\" rel=\"external nofollow\"\u003e3D product\u003c/a\u003e models like soda \u003ca href=\"https://manayerbamate.com/\" rel=\"external nofollow\"\u003ecans\u003c/a\u003e. Here's a demo that simplifies down the approach.\u003cbr\u003e\n\t\t\u003cbr\u003e\n\t\tWe will be using ScrollTrigger and the FLIP plugin.\n\t\u003c/p\u003e\n\u003c/div\u003e\n\n\u003cul\u003e\n\t\u003cli\u003e\n\t\t\u003ch2\u003e\n\t\t\tTreat your 3D canvas like a card you can move\n\t\t\u003c/h2\u003e\n\n\t\t\u003cp\u003e\n\t\t\tIn this example we're creating a small Three.js scene and rendering it into a \u003ccode\u003e\u0026lt;canvas/\u0026gt; \u003c/code\u003eelement. Inside this canvas is a cube, but you could swap in any 3D content. The important part is that the canvas element is the thing we're going to tell Flip plugin to move.\u003cbr\u003e\n\t\t\t\u003cbr\u003e\n\t\t\tWe added a few marker elements in the layout. These markers are just empty targets that represent the positions you want to move to. Make sure they exist in the normal flow and have measurable size.\n\t\t\u003c/p\u003e\n\n\t\t\u003cpre class=\"ipsCode prettyprint lang-html prettyprinted\" id=\"ips_uid_4520_11\" style=\"\"\u003e\u003cspan class=\"tag\"\u003e\u0026lt;div\u003c/span\u003e\u003cspan class=\"pln\"\u003e \u003c/span\u003e\u003cspan class=\"atn\"\u003eclass\u003c/span\u003e\u003cspan class=\"pun\"\u003e=\u003c/span\u003e\u003cspan class=\"atv\"\u003e\"main\"\u003c/span\u003e\u003cspan class=\"tag\"\u003e\u0026gt;\u003c/span\u003e\u003cspan class=\"pln\"\u003e\n  \u003c/span\u003e\u003cspan class=\"tag\"\u003e\u0026lt;div\u003c/span\u003e\u003cspan class=\"pln\"\u003e \u003c/span\u003e\u003cspan class=\"atn\"\u003eclass\u003c/span\u003e\u003cspan class=\"pun\"\u003e=\u003c/span\u003e\u003cspan class=\"atv\"\u003e\"container initial\"\u003c/span\u003e\u003cspan class=\"tag\"\u003e\u0026gt;\u003c/span\u003e\u003cspan class=\"pln\"\u003e\n    \u003c/span\u003e\u003cspan class=\"tag\"\u003e\u0026lt;canvas/\u0026gt;\u003c/span\u003e\u003cspan class=\"pln\"\u003e \n  \u003c/span\u003e\u003cspan class=\"tag\"\u003e\u0026lt;/div\u0026gt;\u003c/span\u003e\u003cspan class=\"pln\"\u003e\n\n  \u003c/span\u003e\u003cspan class=\"tag\"\u003e\u0026lt;div\u003c/span\u003e\u003cspan class=\"pln\"\u003e \u003c/span\u003e\u003cspan class=\"atn\"\u003eclass\u003c/span\u003e\u003cspan class=\"pun\"\u003e=\u003c/span\u003e\u003cspan class=\"atv\"\u003e\"container second\"\u003c/span\u003e\u003cspan class=\"tag\"\u003e\u0026gt;\u003c/span\u003e\u003cspan class=\"pln\"\u003e\n    \u003c/span\u003e\u003cspan class=\"tag\"\u003e\u0026lt;div\u003c/span\u003e\u003cspan class=\"pln\"\u003e \u003c/span\u003e\u003cspan class=\"atn\"\u003eclass\u003c/span\u003e\u003cspan class=\"pun\"\u003e=\u003c/span\u003e\u003cspan class=\"atv\"\u003e\"marker\"\u003c/span\u003e\u003cspan class=\"tag\"\u003e\u0026gt;\u0026lt;/div\u0026gt;\u003c/span\u003e\u003cspan class=\"pln\"\u003e\n  \u003c/span\u003e\u003cspan class=\"tag\"\u003e\u0026lt;/div\u0026gt;\u003c/span\u003e\u003cspan class=\"pln\"\u003e\n\n  \u003c/span\u003e\u003cspan class=\"tag\"\u003e\u0026lt;div\u003c/span\u003e\u003cspan class=\"pln\"\u003e \u003c/span\u003e\u003cspan class=\"atn\"\u003eclass\u003c/span\u003e\u003cspan class=\"pun\"\u003e=\u003c/span\u003e\u003cspan class=\"atv\"\u003e\"container third\"\u003c/span\u003e\u003cspan class=\"tag\"\u003e\u0026gt;\u003c/span\u003e\u003cspan class=\"pln\"\u003e\n    \u003c/span\u003e\u003cspan class=\"tag\"\u003e\u0026lt;div\u003c/span\u003e\u003cspan class=\"pln\"\u003e \u003c/span\u003e\u003cspan class=\"atn\"\u003eclass\u003c/span\u003e\u003cspan class=\"pun\"\u003e=\u003c/span\u003e\u003cspan class=\"atv\"\u003e\"marker\"\u003c/span\u003e\u003cspan class=\"tag\"\u003e\u0026gt;\u0026lt;/div\u0026gt;\u003c/span\u003e\u003cspan class=\"pln\"\u003e\n  \u003c/span\u003e\u003cspan class=\"tag\"\u003e\u0026lt;/div\u0026gt;\u003c/span\u003e\u003cspan class=\"pln\"\u003e\n\u003c/span\u003e\u003cspan class=\"tag\"\u003e\u0026lt;/div\u0026gt;\u003c/span\u003e\u003c/pre\u003e\n\n\t\t\u003cp\u003e\n\t\t\t \n\t\t\u003c/p\u003e\n\t\u003c/li\u003e\n\t\u003cli\u003e\n\t\t\u003ch2\u003e\n\t\t\tFlip between markers using \u003ccode data-end=\"1648\" data-start=\"1631\"\u003eFlip.getState()\u003c/code\u003e + \u003ccode data-end=\"1663\" data-start=\"1651\"\u003eFlip.fit()\u003c/code\u003e\n\t\t\u003c/h2\u003e\n\n\t\t\u003cp\u003e\n\t\t\tCapture the states of your marker targets, then let \u003ccode data-end=\"1728\" data-start=\"1716\"\u003eFlip.fit()\u003c/code\u003e animate the canvas between them. Flip will measure each the \u003cstrong data-end=\"568\" data-start=\"549\"\u003emarker elements\u003c/strong\u003e and then fit the \u003cstrong data-end=\"600\" data-start=\"590\"\u003ecanvas\u003c/strong\u003e to each marker’s state.\u003cbr\u003e\n\t\t\t\u003cbr\u003e\n\t\t\tWe're also adding some extra animations to the timeline to affect the rotation of the cube.\n\t\t\u003c/p\u003e\n\n\t\t\u003cpre class=\"ipsCode prettyprint lang-javascript prettyprinted\" id=\"ips_uid_4520_9\" style=\"\"\u003e\u003cspan class=\"kwd\"\u003econst\u003c/span\u003e\u003cspan class=\"pln\"\u003e s2 \u003c/span\u003e\u003cspan class=\"pun\"\u003e=\u003c/span\u003e\u003cspan class=\"pln\"\u003e \u003c/span\u003e\u003cspan class=\"typ\"\u003eFlip\u003c/span\u003e\u003cspan class=\"pun\"\u003e.\u003c/span\u003e\u003cspan class=\"pln\"\u003egetState\u003c/span\u003e\u003cspan class=\"pun\"\u003e(\u003c/span\u003e\u003cspan class=\"str\"\u003e\".second .marker\"\u003c/span\u003e\u003cspan class=\"pun\"\u003e);\u003c/span\u003e\u003cspan class=\"pln\"\u003e\n\u003c/span\u003e\u003cspan class=\"kwd\"\u003econst\u003c/span\u003e\u003cspan class=\"pln\"\u003e s3 \u003c/span\u003e\u003cspan class=\"pun\"\u003e=\u003c/span\u003e\u003cspan class=\"pln\"\u003e \u003c/span\u003e\u003cspan class=\"typ\"\u003eFlip\u003c/span\u003e\u003cspan class=\"pun\"\u003e.\u003c/span\u003e\u003cspan class=\"pln\"\u003egetState\u003c/span\u003e\u003cspan class=\"pun\"\u003e(\u003c/span\u003e\u003cspan class=\"str\"\u003e\".third .marker\"\u003c/span\u003e\u003cspan class=\"pun\"\u003e);\u003c/span\u003e\u003cspan class=\"pln\"\u003e\n\n\u003c/span\u003e\u003cspan class=\"kwd\"\u003econst\u003c/span\u003e\u003cspan class=\"pln\"\u003e tl \u003c/span\u003e\u003cspan class=\"pun\"\u003e=\u003c/span\u003e\u003cspan class=\"pln\"\u003e gsap\u003c/span\u003e\u003cspan class=\"pun\"\u003e.\u003c/span\u003e\u003cspan class=\"pln\"\u003etimeline\u003c/span\u003e\u003cspan class=\"pun\"\u003e({...});\u003c/span\u003e\u003cspan class=\"pln\"\u003e\n\n\u003c/span\u003e\u003cspan class=\"com\"\u003e// Hop to second marker and rotate the cube\u003c/span\u003e\u003cspan class=\"pln\"\u003e\ntl\u003c/span\u003e\u003cspan class=\"pun\"\u003e.\u003c/span\u003e\u003cspan class=\"pln\"\u003eadd\u003c/span\u003e\u003cspan class=\"pun\"\u003e(\u003c/span\u003e\u003cspan class=\"typ\"\u003eFlip\u003c/span\u003e\u003cspan class=\"pun\"\u003e.\u003c/span\u003e\u003cspan class=\"pln\"\u003efit\u003c/span\u003e\u003cspan class=\"pun\"\u003e(\u003c/span\u003e\u003cspan class=\"pln\"\u003ecanvasEl\u003c/span\u003e\u003cspan class=\"pun\"\u003e,\u003c/span\u003e\u003cspan class=\"pln\"\u003e s2\u003c/span\u003e\u003cspan class=\"pun\"\u003e,\u003c/span\u003e\u003cspan class=\"pln\"\u003e \u003c/span\u003e\u003cspan class=\"pun\"\u003e{\u003c/span\u003e\u003cspan class=\"pln\"\u003e duration\u003c/span\u003e\u003cspan class=\"pun\"\u003e:\u003c/span\u003e\u003cspan class=\"pln\"\u003e \u003c/span\u003e\u003cspan class=\"lit\"\u003e1\u003c/span\u003e\u003cspan class=\"pun\"\u003e,\u003c/span\u003e\u003cspan class=\"pln\"\u003e ease\u003c/span\u003e\u003cspan class=\"pun\"\u003e:\u003c/span\u003e\u003cspan class=\"pln\"\u003e \u003c/span\u003e\u003cspan class=\"str\"\u003e\"none\"\u003c/span\u003e\u003cspan class=\"pln\"\u003e \u003c/span\u003e\u003cspan class=\"pun\"\u003e}))\u003c/span\u003e\u003cspan class=\"pln\"\u003e\n\u003c/span\u003e\u003cspan class=\"pun\"\u003e.\u003c/span\u003e\u003cspan class=\"pln\"\u003eto\u003c/span\u003e\u003cspan class=\"pun\"\u003e(\u003c/span\u003e\u003cspan class=\"pln\"\u003emesh\u003c/span\u003e\u003cspan class=\"pun\"\u003e.\u003c/span\u003e\u003cspan class=\"pln\"\u003erotation\u003c/span\u003e\u003cspan class=\"pun\"\u003e,\u003c/span\u003e\u003cspan class=\"pln\"\u003e \u003c/span\u003e\u003cspan class=\"pun\"\u003e{\u003c/span\u003e\u003cspan class=\"pln\"\u003e \n  x\u003c/span\u003e\u003cspan class=\"pun\"\u003e:\u003c/span\u003e\u003cspan class=\"pln\"\u003e \u003c/span\u003e\u003cspan class=\"pun\"\u003e`+=\u003c/span\u003e\u003cspan class=\"pln\"\u003e$\u003c/span\u003e\u003cspan class=\"pun\"\u003e{\u003c/span\u003e\u003cspan class=\"typ\"\u003eMath\u003c/span\u003e\u003cspan class=\"pun\"\u003e.\u003c/span\u003e\u003cspan class=\"pln\"\u003ePI\u003c/span\u003e\u003cspan class=\"pun\"\u003e}`,\u003c/span\u003e\u003cspan class=\"pln\"\u003e \n  y\u003c/span\u003e\u003cspan class=\"pun\"\u003e:\u003c/span\u003e\u003cspan class=\"pln\"\u003e \u003c/span\u003e\u003cspan class=\"pun\"\u003e`+=\u003c/span\u003e\u003cspan class=\"pln\"\u003e$\u003c/span\u003e\u003cspan class=\"pun\"\u003e{\u003c/span\u003e\u003cspan class=\"typ\"\u003eMath\u003c/span\u003e\u003cspan class=\"pun\"\u003e.\u003c/span\u003e\u003cspan class=\"pln\"\u003ePI\u003c/span\u003e\u003cspan class=\"pun\"\u003e}`,\u003c/span\u003e\u003cspan class=\"pln\"\u003e \n  duration\u003c/span\u003e\u003cspan class=\"pun\"\u003e:\u003c/span\u003e\u003cspan class=\"pln\"\u003e \u003c/span\u003e\u003cspan class=\"lit\"\u003e1\u003c/span\u003e\u003cspan class=\"pun\"\u003e,\u003c/span\u003e\u003cspan class=\"pln\"\u003e \n  ease\u003c/span\u003e\u003cspan class=\"pun\"\u003e:\u003c/span\u003e\u003cspan class=\"pln\"\u003e \u003c/span\u003e\u003cspan class=\"str\"\u003e\"none\"\u003c/span\u003e\u003cspan class=\"pln\"\u003e \n\u003c/span\u003e\u003cspan class=\"pun\"\u003e},\u003c/span\u003e\u003cspan class=\"str\"\u003e\"\u0026lt;\"\u003c/span\u003e\u003cspan class=\"pun\"\u003e)\u003c/span\u003e\u003cspan class=\"pln\"\u003e\n\n\u003c/span\u003e\u003cspan class=\"com\"\u003e// A little breathing room between hops\u003c/span\u003e\u003cspan class=\"pln\"\u003e\n\u003c/span\u003e\u003cspan class=\"pun\"\u003e.\u003c/span\u003e\u003cspan class=\"pln\"\u003eaddLabel\u003c/span\u003e\u003cspan class=\"pun\"\u003e(\u003c/span\u003e\u003cspan class=\"str\"\u003e\"mid\"\u003c/span\u003e\u003cspan class=\"pun\"\u003e,\u003c/span\u003e\u003cspan class=\"pln\"\u003e \u003c/span\u003e\u003cspan class=\"str\"\u003e\"+=0.5\"\u003c/span\u003e\u003cspan class=\"pun\"\u003e)\u003c/span\u003e\u003cspan class=\"pln\"\u003e\n\n\u003c/span\u003e\u003cspan class=\"com\"\u003e// Hop to third marker and rotate again\u003c/span\u003e\u003cspan class=\"pln\"\u003e\n\u003c/span\u003e\u003cspan class=\"pun\"\u003e.\u003c/span\u003e\u003cspan class=\"pln\"\u003eadd\u003c/span\u003e\u003cspan class=\"pun\"\u003e(\u003c/span\u003e\u003cspan class=\"typ\"\u003eFlip\u003c/span\u003e\u003cspan class=\"pun\"\u003e.\u003c/span\u003e\u003cspan class=\"pln\"\u003efit\u003c/span\u003e\u003cspan class=\"pun\"\u003e(\u003c/span\u003e\u003cspan class=\"pln\"\u003ecanvasEl\u003c/span\u003e\u003cspan class=\"pun\"\u003e,\u003c/span\u003e\u003cspan class=\"pln\"\u003e s3\u003c/span\u003e\u003cspan class=\"pun\"\u003e,\u003c/span\u003e\u003cspan class=\"pln\"\u003e \u003c/span\u003e\u003cspan class=\"pun\"\u003e{\u003c/span\u003e\u003cspan class=\"pln\"\u003e duration\u003c/span\u003e\u003cspan class=\"pun\"\u003e:\u003c/span\u003e\u003cspan class=\"pln\"\u003e \u003c/span\u003e\u003cspan class=\"lit\"\u003e1\u003c/span\u003e\u003cspan class=\"pun\"\u003e,\u003c/span\u003e\u003cspan class=\"pln\"\u003e ease\u003c/span\u003e\u003cspan class=\"pun\"\u003e:\u003c/span\u003e\u003cspan class=\"pln\"\u003e \u003c/span\u003e\u003cspan class=\"str\"\u003e\"none\"\u003c/span\u003e\u003cspan class=\"pln\"\u003e \u003c/span\u003e\u003cspan class=\"pun\"\u003e}),\u003c/span\u003e\u003cspan class=\"pln\"\u003e \u003c/span\u003e\u003cspan class=\"str\"\u003e\"mid\"\u003c/span\u003e\u003cspan class=\"pun\"\u003e)\u003c/span\u003e\u003cspan class=\"pln\"\u003e\n\u003c/span\u003e\u003cspan class=\"pun\"\u003e.\u003c/span\u003e\u003cspan class=\"pln\"\u003eto\u003c/span\u003e\u003cspan class=\"pun\"\u003e(\u003c/span\u003e\u003cspan class=\"pln\"\u003emesh\u003c/span\u003e\u003cspan class=\"pun\"\u003e.\u003c/span\u003e\u003cspan class=\"pln\"\u003erotation\u003c/span\u003e\u003cspan class=\"pun\"\u003e,{\u003c/span\u003e\u003cspan class=\"pln\"\u003e \n  x\u003c/span\u003e\u003cspan class=\"pun\"\u003e:\u003c/span\u003e\u003cspan class=\"pln\"\u003e \u003c/span\u003e\u003cspan class=\"pun\"\u003e`+=\u003c/span\u003e\u003cspan class=\"pln\"\u003e$\u003c/span\u003e\u003cspan class=\"pun\"\u003e{\u003c/span\u003e\u003cspan class=\"typ\"\u003eMath\u003c/span\u003e\u003cspan class=\"pun\"\u003e.\u003c/span\u003e\u003cspan class=\"pln\"\u003ePI\u003c/span\u003e\u003cspan class=\"pun\"\u003e}`,\u003c/span\u003e\u003cspan class=\"pln\"\u003e \n  y\u003c/span\u003e\u003cspan class=\"pun\"\u003e:\u003c/span\u003e\u003cspan class=\"pln\"\u003e \u003c/span\u003e\u003cspan class=\"pun\"\u003e`+=\u003c/span\u003e\u003cspan class=\"pln\"\u003e$\u003c/span\u003e\u003cspan class=\"pun\"\u003e{\u003c/span\u003e\u003cspan class=\"typ\"\u003eMath\u003c/span\u003e\u003cspan class=\"pun\"\u003e.\u003c/span\u003e\u003cspan class=\"pln\"\u003ePI\u003c/span\u003e\u003cspan class=\"pun\"\u003e}`,\u003c/span\u003e\u003cspan class=\"pln\"\u003e \n  duration\u003c/span\u003e\u003cspan class=\"pun\"\u003e:\u003c/span\u003e\u003cspan class=\"pln\"\u003e \u003c/span\u003e\u003cspan class=\"lit\"\u003e1\u003c/span\u003e\u003cspan class=\"pun\"\u003e,\u003c/span\u003e\u003cspan class=\"pln\"\u003e \n  ease\u003c/span\u003e\u003cspan class=\"pun\"\u003e:\u003c/span\u003e\u003cspan class=\"pln\"\u003e \u003c/span\u003e\u003cspan class=\"str\"\u003e\"none\"\u003c/span\u003e\u003cspan class=\"pln\"\u003e \n\u003c/span\u003e\u003cspan class=\"pun\"\u003e},\u003c/span\u003e\u003cspan class=\"str\"\u003e\"\u0026lt;\"\u003c/span\u003e\u003cspan class=\"pun\"\u003e);\u003c/span\u003e\u003c/pre\u003e\n\n\t\t\u003cp\u003e\n\t\t\t \n\t\t\u003c/p\u003e\n\t\u003c/li\u003e\n\t\u003cli\u003e\n\t\t\u003ch2\u003e\n\t\t\tClean resizing with \u003ccode data-end=\"2825\" data-start=\"2809\"\u003e\u003ca href=\"https://greensock.com/docs/v3/GSAP/gsap.context()\" rel=\"external nofollow\"\u003egsap.context()\u003c/a\u003e\u003c/code\u003e\n\t\t\u003c/h2\u003e\n\n\t\t\u003cp\u003e\n\t\t\tThis bit is \u003cstrong\u003e\u003cem\u003every important\u003c/em\u003e\u003c/strong\u003e. ScrollTrigger pre-calculates and caches values for performance, whereas Flip is \u003ca href=\"https://gsap.com/docs/v3/Plugins/Flip/#how-does-flip-work\" rel=\"external nofollow\"\u003edynamic\u003c/a\u003e and needs to measure the current layout at the time the animation fires. If the page resizes and you do not rebuild the timeline, Flip will be using stale measurements and your animations will look broken.\u003cbr\u003e\n\t\t\t\u003cbr\u003e\n\t\t\tTo make this nice and easy we wrap our animations in a \u003ccode data-end=\"2946\" data-start=\"2930\"\u003e\u003ca href=\"https://greensock.com/docs/v3/GSAP/gsap.context()\" rel=\"external nofollow\"\u003egsap.context()\u003c/a\u003e\u003c/code\u003e. On resize, we call \u003ccode data-end=\"2978\" data-start=\"2964\"\u003ectx.revert()\u003c/code\u003e to clean up any timelines and ScrollTriggers created inside, then rebuild so Flip can re-measure.\n\t\t\u003c/p\u003e\n\n\t\t\u003cpre class=\"ipsCode prettyprint lang-javascript prettyprinted\" id=\"ips_uid_4463_11\" style=\"\"\u003e\u003cspan class=\"kwd\"\u003efunction\u003c/span\u003e\u003cspan class=\"pln\"\u003e buildTimeline\u003c/span\u003e\u003cspan class=\"pun\"\u003e()\u003c/span\u003e\u003cspan class=\"pln\"\u003e \u003c/span\u003e\u003cspan class=\"pun\"\u003e{\u003c/span\u003e\u003cspan class=\"pln\"\u003e\n  ctx \u003c/span\u003e\u003cspan class=\"pun\"\u003e\u0026amp;\u0026amp;\u003c/span\u003e\u003cspan class=\"pln\"\u003e ctx\u003c/span\u003e\u003cspan class=\"pun\"\u003e.\u003c/span\u003e\u003cspan class=\"pln\"\u003erevert\u003c/span\u003e\u003cspan class=\"pun\"\u003e();\u003c/span\u003e\u003cspan class=\"pln\"\u003e \u003c/span\u003e\u003cspan class=\"com\"\u003e// If the context exists, revert it and rebuild so the FLIP animations are recalculated on resize and reflect the new layout\u003c/span\u003e\u003cspan class=\"pln\"\u003e\n  \n  \u003c/span\u003e\u003cspan class=\"com\"\u003e// collect all of our animations in a GSAP context\u003c/span\u003e\u003cspan class=\"pln\"\u003e\n  ctx \u003c/span\u003e\u003cspan class=\"pun\"\u003e=\u003c/span\u003e\u003cspan class=\"pln\"\u003e gsap\u003c/span\u003e\u003cspan class=\"pun\"\u003e.\u003c/span\u003e\u003cspan class=\"pln\"\u003econtext\u003c/span\u003e\u003cspan class=\"pun\"\u003e(()\u003c/span\u003e\u003cspan class=\"pln\"\u003e \u003c/span\u003e\u003cspan class=\"pun\"\u003e=\u0026gt;\u003c/span\u003e\u003cspan class=\"pln\"\u003e \u003c/span\u003e\u003cspan class=\"pun\"\u003e{\u003c/span\u003e\u003cspan class=\"pln\"\u003e\n    \u003c/span\u003e\u003cspan class=\"kwd\"\u003econst\u003c/span\u003e\u003cspan class=\"pln\"\u003e tl \u003c/span\u003e\u003cspan class=\"pun\"\u003e=\u003c/span\u003e\u003cspan class=\"pln\"\u003e gsap\u003c/span\u003e\u003cspan class=\"pun\"\u003e.\u003c/span\u003e\u003cspan class=\"pln\"\u003etimeline\u003c/span\u003e\u003cspan class=\"pun\"\u003e({\u003c/span\u003e\u003cspan class=\"pln\"\u003e\n      scrollTrigger\u003c/span\u003e\u003cspan class=\"pun\"\u003e:\u003c/span\u003e\u003cspan class=\"pln\"\u003e \u003c/span\u003e\u003cspan class=\"pun\"\u003e{\u003c/span\u003e\u003cspan class=\"pln\"\u003e\n        start\u003c/span\u003e\u003cspan class=\"pun\"\u003e:\u003c/span\u003e\u003cspan class=\"pln\"\u003e \u003c/span\u003e\u003cspan class=\"lit\"\u003e0\u003c/span\u003e\u003cspan class=\"pun\"\u003e,\u003c/span\u003e\u003cspan class=\"pln\"\u003e\n        end\u003c/span\u003e\u003cspan class=\"pun\"\u003e:\u003c/span\u003e\u003cspan class=\"pln\"\u003e \u003c/span\u003e\u003cspan class=\"str\"\u003e\"max\"\u003c/span\u003e\u003cspan class=\"pun\"\u003e,\u003c/span\u003e\u003cspan class=\"pln\"\u003e\n        scrub\u003c/span\u003e\u003cspan class=\"pun\"\u003e:\u003c/span\u003e\u003cspan class=\"pln\"\u003e \u003c/span\u003e\u003cspan class=\"lit\"\u003e2\u003c/span\u003e\u003cspan class=\"pln\"\u003e\n      \u003c/span\u003e\u003cspan class=\"pun\"\u003e}\u003c/span\u003e\u003cspan class=\"pln\"\u003e\n    \u003c/span\u003e\u003cspan class=\"pun\"\u003e});\u003c/span\u003e\u003cspan class=\"pln\"\u003e\n    \u003c/span\u003e\u003cspan class=\"pun\"\u003e...\u003c/span\u003e\u003cspan class=\"pln\"\u003e\n  \u003c/span\u003e\u003cspan class=\"pun\"\u003e});\u003c/span\u003e\u003cspan class=\"pln\"\u003e\n\u003c/span\u003e\u003cspan class=\"pun\"\u003e}\u003c/span\u003e\u003cspan class=\"pln\"\u003e\n\naddEventListener\u003c/span\u003e\u003cspan class=\"pun\"\u003e(\u003c/span\u003e\u003cspan class=\"str\"\u003e\"resize\"\u003c/span\u003e\u003cspan class=\"pun\"\u003e,\u003c/span\u003e\u003cspan class=\"pln\"\u003e \u003c/span\u003e\u003cspan class=\"pun\"\u003e()\u003c/span\u003e\u003cspan class=\"pln\"\u003e \u003c/span\u003e\u003cspan class=\"pun\"\u003e=\u0026gt;\u003c/span\u003e\u003cspan class=\"pln\"\u003e \u003c/span\u003e\u003cspan class=\"pun\"\u003e{\u003c/span\u003e\u003cspan class=\"pln\"\u003e\n  buildTimeline\u003c/span\u003e\u003cspan class=\"pun\"\u003e();\u003c/span\u003e\u003cspan class=\"pln\"\u003e\n\u003c/span\u003e\u003cspan class=\"pun\"\u003e});\u003c/span\u003e\u003c/pre\u003e\n\n\t\t\u003cp\u003e\n\t\t\t\u003cbr\u003e\n\t\t\t \n\t\t\u003c/p\u003e\n\t\u003c/li\u003e\n\u003c/ul\u003e\n"])

